<script setup lang="ts">
import { ref, onMounted } from 'vue'
import { ElMessage } from 'element-plus'
import {
  Camera, CircleCheck, Collection, Search, MostlyCloudy, Check, Link,
  EditPen, List, OfficeBuilding, Box, Warning
} from '@element-plus/icons-vue'

// 物料信息类型
interface Material {
  code: string
  name: string
  batchNo: string
  tank: string
  theoryQty: number
  unit: string
}

// 投料记录类型
interface InputRecord {
  time: string
  materialName: string
  batchNo: string
  theoryQty: number
  actualQty: number
  unit: string
  operator: string
  status: string
}

// 罐体类型
interface Tank {
  id: string
  name: string
  hasMaterial: boolean
  materialName?: string
  batchNo?: string
  remainingQty?: number
  unit?: string
}

// 响应式数据
const scanForm = ref({
  barcode: ''
})
const weighForm = ref({
  actualQty: 0
})
const scanLoading = ref(false)
const submitLoading = ref(false)
const recordLoading = ref(false)
const scannedMaterial = ref<Material | null>(null)
const todayRecords = ref<InputRecord[]>([])
const scaleDialogVisible = ref(false)
const scaleConnected = ref(false)
const connectLoading = ref(false)
const scaleForm = ref({
  type: 'rs232',
  port: 'COM1',
  baudRate: '9600'
})

// 罐体列表
const tankList = ref<Tank[]>([
  { id: '1', name: '罐体 A1', hasMaterial: true, materialName: '液态基胶-001', batchNo: '20240605001', remainingQty: 2500, unit: 'L' },
  { id: '2', name: '罐体 A2', hasMaterial: true, materialName: '液态基胶-002', batchNo: '20240605002', remainingQty: 1800, unit: 'L' },
  { id: '3', name: '罐体 B1', hasMaterial: true, materialName: '调色液-红色', batchNo: '20240605003', remainingQty: 500, unit: 'L' },
  { id: '4', name: '罐体 B2', hasMaterial: false },
  { id: '5', name: '罐体 C1', hasMaterial: true, materialName: '粉料-碳酸钙', batchNo: '20240605004', remainingQty: 800, unit: 'kg' },
  { id: '6', name: '罐体 C2', hasMaterial: false },
  { id: '7', name: '罐体 D1', hasMaterial: true, materialName: '小料-助剂A', batchNo: '20240605005', remainingQty: 50, unit: 'kg' },
  { id: '8', name: '罐体 D2', hasMaterial: false }
])

// 开始扫码（模拟）
const handleStartScan = () => {
  scanLoading.value = true
  ElMessage.info('正在启动扫码...')

  // 模拟扫码过程
  setTimeout(() => {
    // 随机生成一个条码
    const randomBarcode = 'BC' + Date.now().toString().slice(-8)
    scanForm.value.barcode = randomBarcode
    scanLoading.value = false
    ElMessage.success('扫码成功')

    // 自动识别物料
    handleScan()
  }, 1500)
}

// 模拟扫码识别
const handleScan = () => {
  if (!scanForm.value.barcode) {
    ElMessage.warning('请输入物料条码')
    return
  }
  scanLoading.value = true
  // 模拟扫码识别
  setTimeout(() => {
    // 根据条码生成不同的物料信息
    const barcode = scanForm.value.barcode
    const materialTypes = [
      { name: '液态基胶', tank: '罐体 A1', unit: 'L', theoryQty: 500 },
      { name: '调色液-红色', tank: '罐体 B1', unit: 'L', theoryQty: 50 },
      { name: '粉料-碳酸钙', tank: '罐体 C1', unit: 'kg', theoryQty: 100 },
      { name: '小料-助剂A', tank: '罐体 D1', unit: 'kg', theoryQty: 5 }
    ]
    const typeIndex = barcode.charCodeAt(barcode.length - 1) % 4
    const materialType = materialTypes[typeIndex]

    scannedMaterial.value = {
      code: 'MAT-' + barcode.slice(-6),
      name: materialType.name + '-' + barcode.slice(-3),
      batchNo: 'BT' + new Date().toISOString().slice(0, 10).replace(/-/g, '') + String(Math.floor(Math.random() * 900) + 100),
      tank: materialType.tank,
      theoryQty: materialType.theoryQty,
      unit: materialType.unit
    }
    weighForm.value.actualQty = scannedMaterial.value.theoryQty
    scanLoading.value = false
    ElMessage.success('物料识别成功')
  }, 800)
}

// 确认投料
const handleWeighConfirm = () => {
  if (!scannedMaterial.value) return
  submitLoading.value = true
  // 模拟提交
  setTimeout(() => {
    const record: InputRecord = {
      time: new Date().toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' }),
      materialName: scannedMaterial.value.name,
      batchNo: scannedMaterial.value.batchNo,
      theoryQty: scannedMaterial.value.theoryQty,
      actualQty: weighForm.value.actualQty,
      unit: scannedMaterial.value.unit,
      operator: '操作员张三',
      status: '已确认'
    }
    todayRecords.value.unshift(record)
    submitLoading.value = false
    ElMessage.success('投料记录已保存')
    // 重置表单
    scanForm.value.barcode = ''
    scannedMaterial.value = null
    weighForm.value.actualQty = 0
  }, 500)
}

// 连接电子秤
const handleConnectScale = () => {
  scaleDialogVisible.value = true
}

// 确认连接电子秤
const handleConnectScaleConfirm = () => {
  connectLoading.value = true
  setTimeout(() => {
    scaleConnected.value = true
    connectLoading.value = false
    scaleDialogVisible.value = false
    ElMessage.success('电子秤连接成功')
  }, 1000)
}

// 手动录入
const handleManualInput = () => {
  ElMessage.info('请直接输入实际重量')
}

// 加载今日记录
const loadTodayRecords = () => {
  recordLoading.value = true
  setTimeout(() => {
    todayRecords.value = [
      { time: '08:30', materialName: '液态基胶-001', batchNo: 'BT20240605001', theoryQty: 500, actualQty: 502, unit: 'L', operator: '张三', status: '已确认' },
      { time: '08:45', materialName: '调色液-红色', batchNo: 'BT20240605003', theoryQty: 50, actualQty: 49.5, unit: 'L', operator: '张三', status: '已确认' },
      { time: '09:10', materialName: '粉料-碳酸钙', batchNo: 'BT20240605004', theoryQty: 100, actualQty: 101, unit: 'kg', operator: '李四', status: '已确认' },
      { time: '09:35', materialName: '小料-助剂A', batchNo: 'BT20240605005', theoryQty: 5, actualQty: 5.1, unit: 'kg', operator: '李四', status: '已确认' }
    ]
    recordLoading.value = false
  }, 500)
}

onMounted(() => {
  loadTodayRecords()
})
</script>

